226: func isObsoleteDev(dev string, devices []string) bool {
227: 	// exclude devices we never attach to/from_netdev to.
228: 	for _, prefix := range defaults.ExcludedDevicePrefixes {
229: 		if strings.HasPrefix(dev, prefix) {
230: 			return false
231: 		}
232: 	}
233: 
234: 	// exclude devices that will still be managed going forward.
235: 	for _, d := range devices {
236: 		if dev == d {
237: 			return false
238: 		}
239: 	}
240: 
241: 	return true
242: }
