687: // ReloadDatapath reloads the BPF datapath programs for the specified endpoint.
688: //
689: // It attempts to find a pre-compiled
690: // template datapath object to use, to avoid a costly compile operation.
691: // Only if there is no existing template that has the same configuration
692: // parameters as the specified endpoint, this function will compile a new
693: // template for this configuration.
694: //
695: // This function will block if the cache does not contain an entry for the
696: // same EndpointConfiguration and multiple goroutines attempt to concurrently
697: // CompileOrLoad with the same configuration parameters. When the first
698: // goroutine completes compilation of the template, all other CompileOrLoad
699: // invocations will be released.
700: func (l *loader) ReloadDatapath(ctx context.Context, ep datapath.Endpoint, cfg *datapath.LocalNodeConfiguration, stats *metrics.SpanStat) (string, error) {
701: 	dirs := directoryInfo{
702: 		Library: option.Config.BpfDir,
703: 		Runtime: option.Config.StateDir,
704: 		State:   ep.StateDir(),
705: 		Output:  ep.StateDir(),
706: 	}
707: 
708: 	spec, hash, err := l.templateCache.fetchOrCompile(ctx, cfg, ep, &dirs, stats)
709: 	if err != nil {
710: 		return "", err
711: 	}
712: 
713: 	if ep.IsHost() {
714: 		// Reload bpf programs on cilium_host and cilium_net.
715: 		stats.BpfLoadProg.Start()
716: 		err = reloadHostEndpoint(cfg, ep, spec)
717: 		stats.BpfLoadProg.End(err == nil)
718: 
719: 		l.hostDpInitializedOnce.Do(func() {
720: 			log.Debug("Initialized host datapath")
721: 			close(l.hostDpInitialized)
722: 		})
723: 
724: 		return hash, err
725: 	}
726: 
727: 	// Reload an lxc endpoint program.
728: 	stats.BpfLoadProg.Start()
729: 	err = reloadEndpoint(ep, spec)
730: 	stats.BpfLoadProg.End(err == nil)
731: 	return hash, err
732: }
