153: const (
154: 	sizeofPolicyKey = int(unsafe.Sizeof(PolicyKey{}))
155: 	sizeofPrefixlen = int(unsafe.Sizeof(PolicyKey{}.Prefixlen))
156: 	sizeofNexthdr   = int(unsafe.Sizeof(PolicyKey{}.Nexthdr))
157: 	sizeofDestPort  = int(unsafe.Sizeof(PolicyKey{}.DestPortNetwork))
